fn render(c : Ctx) -> vec3f {
  var col = pal(0.6 + fbm(c.q * 2.0 + c.t * 0.05) * 0.3) * fbm(c.q * 3.0 + c.t * 0.02) * 0.25;
  col += vec3f(1.0) * img(c.uv).r * 0.12;
  return col * c.intensity;
}

