fn instancePos(idx : f32, t : f32) -> vec4f {
  let a = idx / 12.0 * 6.2831 + t * 0.4;
  return vec4f(cos(a) * 1.9, sin(t * 0.7 + idx) * 0.4, sin(a) * 1.9 - 0.5, 0.5 + spec((i32(idx) * 5) % 64) * 0.4);
}
fn meshColor(idx : f32, n : vec3f, wp : vec3f, t : f32) -> vec3f {
  let l = max(dot(n, normalize(vec3f(0.4, 0.8, 0.3))), 0.1);
  return pal(idx * 0.08 + t * 0.05) * l * (0.5 + U.bands.x);
}

